	top.nsenter("ip", "link", "set", tunDev, "up")

	if !top.pingUntil(concInner, 15*time.Second) {
		t.Fatalf("single-path bond never came up\n--- edge ---\n%s\n--- conc ---\n%s", edge.log(), conc.log())
	}

